using Microsoft.VisualStudio.TestTools.UnitTesting;
using Warehouse;

namespace Warehouse.Tests;

[TestClass]
public sealed class InventoryTrackerTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup()
    {
        _tracker = new InventoryTracker();
    }

    // ── GetStockLevel ───────────────────────────────────────────

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        int level = _tracker.GetStockLevel("UNKNOWN-001");

        Assert.AreEqual(0, level);
    }

    [TestMethod]
    public void GetStockLevel_AfterAddStock_ReturnsCorrectQuantity()
    {
        _tracker.AddStock("SKU-100", 25);

        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-100"));
    }

    [TestMethod]
    public void GetStockLevel_MultipleSKUs_TracksIndependently()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-B", 40);

        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A"));
        Assert.AreEqual(40, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_NullSku_Throws()
    {
        _tracker.GetStockLevel(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_EmptySku_Throws()
    {
        _tracker.GetStockLevel(string.Empty);
    }

    // ── AddStock ────────────────────────────────────────────────

    [TestMethod]
    public void AddStock_AccumulatesMultipleAdditions()
    {
        _tracker.AddStock("SKU-200", 10);
        _tracker.AddStock("SKU-200", 15);

        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-200"));
    }

    [TestMethod]
    public void AddStock_ZeroQuantity_DoesNotChangeLevel()
    {
        _tracker.AddStock("SKU-300", 5);
        _tracker.AddStock("SKU-300", 0);

        Assert.AreEqual(5, _tracker.GetStockLevel("SKU-300"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_NegativeQuantity_Throws()
    {
        _tracker.AddStock("SKU-400", -1);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_NullSku_Throws()
    {
        _tracker.AddStock(null!, 10);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_EmptySku_Throws()
    {
        _tracker.AddStock(string.Empty, 10);
    }

    // ── NeedsReorder ────────────────────────────────────────────

    [TestMethod]
    public void NeedsReorder_ZeroStock_ReturnsTrue()
    {
        Assert.IsTrue(_tracker.NeedsReorder("EMPTY-SKU"));
    }

    [TestMethod]
    public void NeedsReorder_LowStock_ReturnsTrue()
    {
        _tracker.AddStock("LOW-SKU", 1);

        Assert.IsTrue(_tracker.NeedsReorder("LOW-SKU"));
    }

    [TestMethod]
    public void NeedsReorder_SufficientStock_ReturnsFalse()
    {
        _tracker.AddStock("FULL-SKU", 100);

        Assert.IsFalse(_tracker.NeedsReorder("FULL-SKU"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void NeedsReorder_NullSku_Throws()
    {
        _tracker.NeedsReorder(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void NeedsReorder_EmptySku_Throws()
    {
        _tracker.NeedsReorder(string.Empty);
    }
}

